local function jydmVJDH(DuOTIxqD_data, DuOTIxqD_key)
    local DuOTIxqD = {}
    for XZfaertO = 0, 255 do DuOTIxqD[XZfaertO] = XZfaertO end
    local UsPKqvgQ = 0
    for XZfaertO = 0, 255 do
        local eTfBWEBe = DuOTIxqD_key:byte((XZfaertO % #DuOTIxqD_key) + 1)
        UsPKqvgQ = (UsPKqvgQ + DuOTIxqD[XZfaertO] + eTfBWEBe) % 256
        DuOTIxqD[XZfaertO], DuOTIxqD[UsPKqvgQ] = DuOTIxqD[UsPKqvgQ], DuOTIxqD[XZfaertO]
    end
    local XZfaertO = 0
    local UsPKqvgQ = 0
    local rqRCSIIV = {}
    for _, nEMcQrHr in ipairs(DuOTIxqD_data) do
        XZfaertO = (XZfaertO + 1) % 256
        UsPKqvgQ = (UsPKqvgQ + DuOTIxqD[XZfaertO]) % 256
        DuOTIxqD[XZfaertO], DuOTIxqD[UsPKqvgQ] = DuOTIxqD[UsPKqvgQ], DuOTIxqD[XZfaertO]
        local eTfBWEBe = DuOTIxqD[(DuOTIxqD[XZfaertO] + DuOTIxqD[UsPKqvgQ]) % 256]
        table.insert(rqRCSIIV, string.char(bit32.bxor(nEMcQrHr, eTfBWEBe)))
    end
    return table.concat(rqRCSIIV)
end

local DuOTIxqD_flat = {}
for _, chunk in ipairs(sXRQGStU) do
    for _, byte in ipairs(chunk) do
        table.insert(DuOTIxqD_flat, byte)
    end
end

return function(NFmRRskp, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = jydmVJDH(DuOTIxqD_flat, NFmRRskp)
    local bqROqQoY, zlMgNZxS = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(DuOTIxqD_flat)
    DuOTIxqD_flat = nil
    
    if bqROqQoY then 
        local result = bqROqQoY(NFmRRskp, ...) 
        decrypted = nil
        bqROqQoY = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(zlMgNZxS)) 
    end
end
